"""offlinai_latex — Local offline LaTeX → SVG rendering for iOS.

Uses pdftex (cross-compiled C library via lib-tex) + dvisvgm to convert
LaTeX expressions to SVG files. Falls back to Cairo text rendering if
pdftex is unavailable.

Architecture:
  LaTeX source → pdftex (via ctypes) → DVI → dvisvgm → SVG
  Fallback: LaTeX → Unicode conversion → Cairo text_path → SVG
"""

import os
import sys
import ctypes
import tempfile
import pathlib

__version__ = "1.0.0"

# Find the app bundle paths
_this_dir = os.path.dirname(os.path.abspath(__file__))
_app_dir = os.path.dirname(os.path.dirname(os.path.dirname(_this_dir)))
_fw_dir = os.path.join(_app_dir, "Frameworks")
_latex_dir = os.path.join(_app_dir, "Frameworks", "latex")
_texmf_dir = os.path.join(_app_dir, "Frameworks", "latex", "texmf")

# Try alternate paths for iOS app bundle
if not os.path.isdir(_fw_dir):
    _bundle = os.path.dirname(os.path.dirname(_this_dir))
    _fw_dir = os.path.join(_bundle, "Frameworks")
    _latex_dir = os.path.join(_fw_dir, "latex")
    _texmf_dir = os.path.join(_latex_dir, "texmf")

_pdftex_available = False
_pdftex_lib = None
_kpathsea_lib = None


def _load_pdftex():
    """Check if LaTeX engine is available via Swift bridge.

    The Swift LaTeXEngine.shared handles ios_system initialization and
    calls dllpdftexmain properly. Python communicates via file I/O:
    1. Python writes .tex file to temp dir
    2. Python calls the Swift engine via a shared flag file mechanism
    3. Swift compiles and produces SVG
    4. Python reads the SVG
    """
    # Check if the pdftex framework exists (it's loaded by Swift, not Python)
    global _pdftex_available
    pt_path = os.path.join(_fw_dir, "pdftex.framework", "pdftex")
    _pdftex_available = os.path.exists(pt_path)
    return _pdftex_available

    global _pdftex_available, _pdftex_lib, _kpathsea_lib

    # Load kpathsea first (pdftex depends on it)
    kp_path = os.path.join(_fw_dir, "kpathsea.framework", "kpathsea")
    if not os.path.exists(kp_path):
        kp_path = os.path.join(_latex_dir, "kpathsea.xcframework",
                               "ios-arm64", "kpathsea.framework", "kpathsea")
    if os.path.exists(kp_path):
        try:
            _kpathsea_lib = ctypes.CDLL(kp_path, mode=ctypes.RTLD_GLOBAL)
        except OSError:
            pass

    # Load ios_system (pdftex may depend on it)
    ios_sys_path = os.path.join(_fw_dir, "ios_system.framework", "ios_system")
    if os.path.exists(ios_sys_path):
        try:
            ctypes.CDLL(ios_sys_path, mode=ctypes.RTLD_GLOBAL)
        except OSError:
            pass

    # Load pdftex
    pt_path = os.path.join(_fw_dir, "pdftex.framework", "pdftex")
    if not os.path.exists(pt_path):
        pt_path = os.path.join(_latex_dir, "pdftex.xcframework",
                               "ios-arm64", "pdftex.framework", "pdftex")
    if os.path.exists(pt_path):
        try:
            _pdftex_lib = ctypes.CDLL(pt_path, mode=ctypes.RTLD_GLOBAL)
            _pdftex_available = True
        except OSError as e:
            _pdftex_available = False

    return _pdftex_available


def compile_tex(tex_source, output_dir=None):
    """Compile a .tex file using pdftex via ctypes.

    ios_system is initialized by Swift (LaTeXEngine.shared.initialize())
    at app startup, so pdftex can now be called safely from Python.
    """

    if not _pdftex_available:
        _load_pdftex()
    if not _pdftex_available:
        return None

    if output_dir is None:
        output_dir = tempfile.mkdtemp(prefix="offlinai_tex_")

    # If tex_source is a string (not a file path), write it to a file
    if not os.path.exists(tex_source):
        tex_file = os.path.join(output_dir, "input.tex")
        with open(tex_file, 'w') as f:
            f.write(tex_source)
    else:
        tex_file = tex_source

    # Set environment for TeX
    os.environ['TEXMFCNF'] = os.path.join(_texmf_dir, 'web2c')
    os.environ['TEXMFDIST'] = _texmf_dir
    os.environ['TEXMF'] = _texmf_dir

    # Call dllpdftexmain via ctypes
    try:
        func = _pdftex_lib.dllpdftexmain
        func.restype = ctypes.c_int
        func.argtypes = [ctypes.c_int, ctypes.POINTER(ctypes.c_char_p)]

        args = [
            b"pdftex",
            b"--interaction=nonstopmode",
            f"--output-directory={output_dir}".encode(),
            tex_file.encode(),
        ]
        argc = len(args)
        argv = (ctypes.c_char_p * argc)(*args)

        result = func(argc, argv)

        # Find the DVI output
        dvi_file = os.path.join(output_dir, os.path.splitext(os.path.basename(tex_file))[0] + ".dvi")
        if os.path.exists(dvi_file):
            return dvi_file
    except Exception as e:
        pass

    return None


def tex_to_svg(expression, svg_path=None, tex_template_body=None):
    """Convert a LaTeX expression to SVG.

    Tries pdftex → dvisvgm pipeline first, falls back to Cairo.

    Parameters
    ----------
    expression : str
        LaTeX expression (e.g., "E = mc^2")
    svg_path : str or Path, optional
        Output SVG file path. Auto-generated if not specified.
    tex_template_body : str, optional
        Full .tex file content. If None, wraps expression in minimal template.

    Returns
    -------
    pathlib.Path
        Path to the generated SVG file.
    """
    if svg_path is None:
        import hashlib
        h = hashlib.md5(expression.encode()).hexdigest()[:12]
        svg_path = os.path.join(tempfile.gettempdir(), f"tex_{h}.svg")
    svg_path = pathlib.Path(svg_path)

    # Try pdftex pipeline
    if _pdftex_available or _load_pdftex():
        if tex_template_body:
            tex_src = tex_template_body
        else:
            tex_src = (
                "\\documentclass[preview]{standalone}\n"
                "\\usepackage{amsmath}\n"
                "\\usepackage{amssymb}\n"
                "\\begin{document}\n"
                f"${expression}$\n"
                "\\end{document}\n"
            )
        dvi = compile_tex(tex_src)
        if dvi:
            # TODO: Convert DVI to SVG using dvisvgm
            # For now, use the DVI file existence as proof pdftex works
            pass

    # Fallback: Cairo text rendering
    _render_with_cairo(expression, str(svg_path))
    return svg_path


def _render_with_cairo(expression, svg_path):
    """Render LaTeX expression to SVG using Cairo text_path (fallback)."""
    import re

    display = expression
    # LaTeX → Unicode conversion
    display = re.sub(r'\\frac\{([^}]*)\}\{([^}]*)\}', r'(\1)/(\2)', display)
    display = re.sub(r'\\sqrt\{([^}]*)\}', r'√(\1)', display)
    _greek = {'alpha':'α','beta':'β','gamma':'γ','delta':'δ','epsilon':'ε','zeta':'ζ',
              'eta':'η','theta':'θ','lambda':'λ','mu':'μ','pi':'π','sigma':'σ','omega':'ω',
              'phi':'φ','psi':'ψ','Gamma':'Γ','Delta':'Δ','Theta':'Θ','Lambda':'Λ','Omega':'Ω'}
    for name, sym in _greek.items():
        display = display.replace(f'\\{name}', sym)
    display = re.sub(r'\\(sin|cos|tan|log|ln|exp|lim)\b', r'\1', display)
    display = display.replace('\\cdot', '·').replace('\\times', '×').replace('\\pm', '±')
    display = display.replace('\\infty', '∞').replace('\\neq', '≠')
    display = display.replace('\\leq', '≤').replace('\\geq', '≥')
    display = display.replace('\\int', '∫').replace('\\sum', 'Σ')
    display = display.replace('\\partial', '∂').replace('\\nabla', '∇')
    display = display.replace('\\left', '').replace('\\right', '')
    display = re.sub(r'\\[a-zA-Z]+\{([^}]*)\}', r'\1', display)
    display = re.sub(r'\\[a-zA-Z]+', '', display)
    display = re.sub(r'[\$\{\}\\]', '', display).strip() or "?"
    display = re.sub(r'\s+', ' ', display)

    fs = 40
    try:
        import cairo
        # Measure text
        tmp = cairo.ImageSurface(cairo.FORMAT_ARGB32, 1, 1)
        ctx = cairo.Context(tmp)
        ctx.select_font_face("sans-serif", cairo.FONT_SLANT_NORMAL, cairo.FONT_WEIGHT_NORMAL)
        ctx.set_font_size(fs)
        te = ctx.text_extents(display)
        tmp.finish()

        w = max(te.x_advance + 10, 20)
        h = max(fs * 1.5, 20)

        surface = cairo.SVGSurface(svg_path, w, h)
        ctx = cairo.Context(surface)
        ctx.select_font_face("sans-serif", cairo.FONT_SLANT_NORMAL, cairo.FONT_WEIGHT_NORMAL)
        ctx.set_font_size(fs)
        ctx.set_source_rgb(1, 1, 1)
        ctx.move_to(0, fs)
        ctx.text_path(display)
        ctx.fill()
        surface.finish()
    except ImportError:
        # No Cairo either — write minimal SVG
        esc = display.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
        svg = (f'<svg xmlns="http://www.w3.org/2000/svg" width="300" height="60">'
               f'<text x="0" y="40" font-size="40" fill="white">{esc}</text></svg>')
        os.makedirs(os.path.dirname(svg_path) or '.', exist_ok=True)
        with open(svg_path, 'w') as f:
            f.write(svg)
